prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?normId ?origId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  FILTER(STR(?normId) = "6e8e145a4f51488c81c0c89e863a27fa" || STR(?origId) = "6e8e145a4f51488c81c0c89e863a27fa")
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?node ?nodeName ?type ?outDegree WHERE {
  ?node a ?type .
  ?node bbo:name ?nodeName .
  FILTER(CONTAINS(LCASE(STR(?nodeName)), LCASE("Tilaus")) || CONTAINS(LCASE(STR(?nodeName)), LCASE("Ruokailu")))
  {
    SELECT ?node (COUNT(DISTINCT ?flow) as ?outDegree) WHERE {
      ?flow a bbo:SequenceFlow .
      ?flow bbo:has_sourceRef ?node .
    }
    GROUP BY ?node
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gw ?gwName ?gwDir ?inFlows ?outFlows WHERE {
  ?gw a ?gwType .
  FILTER(?gwType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  ?gw bbo:name ?gwName .
  OPTIONAL { ?gw bboExt:gatewayDirection ?gwDir . }
  {
    SELECT ?gw (COUNT(DISTINCT ?inFlow) as ?inFlows) WHERE {
      ?inFlow a bbo:SequenceFlow .
      ?inFlow bbo:has_targetRef ?gw .
    }
    GROUP BY ?gw
  }
  {
    SELECT ?gw (COUNT(DISTINCT ?outFlow) as ?outFlows) WHERE {
      ?outFlow a bbo:SequenceFlow .
      ?outFlow bbo:has_sourceRef ?gw .
    }
    GROUP BY ?gw
  }
}
LIMIT 50

