prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gw ?gwName ?gwDir ?inFlows ?outFlows ?sourceName ?targetName WHERE {
  ?gw a ?gwType .
  FILTER(?gwType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  ?gw bbo:name ?gwName .
  OPTIONAL { ?gw bboExt:gatewayDirection ?gwDir . }
  {
    SELECT ?gw (COUNT(DISTINCT ?inFlow) as ?inFlows) WHERE {
      ?inFlow a bbo:SequenceFlow .
      ?inFlow bbo:has_targetRef ?gw .
    }
    GROUP BY ?gw
  }
  {
    SELECT ?gw (COUNT(DISTINCT ?outFlow) as ?outFlows) WHERE {
      ?outFlow a bbo:SequenceFlow .
      ?outFlow bbo:has_sourceRef ?gw .
    }
    GROUP BY ?gw
  }
  ?outFlow a bbo:SequenceFlow .
  ?outFlow bbo:has_sourceRef ?gw .
  ?outFlow bbo:has_targetRef ?target .
  ?target bbo:name ?targetName .
  FILTER(CONTAINS(LCASE(STR(?targetName)), LCASE("Tilaus")) || CONTAINS(LCASE(STR(?targetName)), LCASE("Ruokailu")))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?stepNum ?elem ?elemName ?type WHERE {
  {
    SELECT ?start ?startName WHERE {
      ?start a bboExt:ChoreographyTask .
      ?start bbo:name ?startName .
      FILTER(CONTAINS(LCASE(STR(?startName)), LCASE("Merkitse varaus")))
    }
  }
  # Step 1: Direct successors of Merkitse varaus
  {
    SELECT ?start ((^bbo:has_sourceRef)/bbo:has_targetRef) as ?elem ?type ?startName WHERE {
      ?start bbo:name ?startName .
      ?elem a ?type .
    }
    FILTER(CONTAINS(LCASE(STR(?startName)), LCASE("Merkitse varaus")))
  }
  UNION
  # Step 2: Get the names
  {
    SELECT 2 as ?stepNum ?elem ?elemName ?type WHERE {
      ?start a bboExt:ChoreographyTask .
      ?start bbo:name ?startName .
      FILTER(CONTAINS(LCASE(STR(?startName)), LCASE("Merkitse varaus")))
      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef) ?elem .
      ?elem a ?type .
      ?elem bbo:name ?elemName .
    }
  }
}
ORDER BY ?stepNum ?elem
LIMIT 50
